# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import os
import pymysql
from flask import Flask, request

app = Flask(__name__)

# Get DB connection details
DB_USER = os.environ.get('DB_USER')
DB_PASS = os.environ.get('DB_PASS')
DB_NAME = os.environ.get('DB_NAME')
DB_CONNECTION_NAME = os.environ.get('DB_CONNECTION_NAME')

# Function to generate SQL query
def generate_sql(params):
    base_query = "SELECT * FROM table_name WHERE"
    for key,value in params.items():
        base_query+= " " + key + " = " + value + " AND"
    return base_query[:-4]  # remove last 'AND'

@app.route('/search', methods=['POST'])
def search():
    try:
        # connect to the google cloud sql
        conn = pymysql.connect(
            user=DB_USER, 
            password=DB_PASS, 
            db=DB_NAME, 
            host=DB_CONNECTION_NAME
        )
        
        # generate query from params
        query = generate_sql(request.json)
        
        # create a cursor
        cursor = conn.cursor()
        cursor.execute(query)
        
        # fetch and return results
        results = cursor.fetchall()
        return str(results)

    except Exception as e:
        return 'Failed to query from db', 500

    finally:
        conn.close()

# Start the Flask application
if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080, debug=True)